text:
{
  "title": "လုံခြုံရေးဆိုင်ရာ အင်တာဗျူး မေးခွန်းများအတွက် သင်တန်းအစီအစဉ်",
  "description": "ဤသင်တန်းသည် လုံခြုံရေးအင်တာဗျူးတွင် မေးမြန်းမည့် မေးခွန်းများကို ရှာဖွေရန်နှင့် ပြင်ဆင်ရန် လိုအပ်သော အချက်အလက်များကို ပေးပါသည်။ သင်သည် လုံခြုံရေးအင်တာဗျူးတွင် အောင်မြင်ရန် လိုအပ်သော အထူးပြု အကြောင်းအရာများကို လေ့လာပါမည်။",
  "modules": [
    {
      "id": "module_1",
      "title": "လုံခြုံရေးအင်တာဗျူးအတွက် အခြေခံသိပ္ပံ",
      "description": "လုံခြုံရေးအင်တာဗျူးတွင် မေးမြန်းမည့် အခြေခံမေးခွန်းများနှင့် အထူးပြု အကြောင်းအရာများကို လေ့လာပါ။"
    },
    {
      "id": "module_2",
      "title": "လုံခြုံရေးအင်တာဗျူးတွင် အထူးပြု မေးခွန်းများ",
      "description": "လုံခြုံရေးအင်တာဗျူးတွင် မေးမြန်းမည့် အထူးပြု မေးခွန်းများနှင့် ၎င်းတို့၏ အကြောင်းအရာများကို ရှာဖွေပါ။"
    },
    {
      "id": "module_3",
      "title": "လုံခြုံရေးအင်တာဗျူးတွင် အောင်မြင်ရန် နည်းလမ်းများ",
      "description": "အင်တာဗျူးအတွက် ပြင်ဆင်ရန် လိုအပ်သော နည်းလမ်းများနှင့် အကြံပြုချက်များကို လေ့လာပါ။"
    },
    {
      "id": "module_4",
      "title": "လက်တွေ့ လေ့လာမှုများနှင့် အကြံပြုချက်များ",
      "description": "လက်တွေ့အခြေအနေများတွင် လုံခြုံရေးအင်တာဗျူးကို အောင်မြင်စွာ ဖြေဆိုရန် လိုအပ်သော လေ့လာမှုများနှင့် အကြံပြုချက်များကို လေ့လာပါ။"
    }
  ]
}
